// src/pages/Home.js
import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import FoodCard from '../components/FoodCard';
import { foodAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';

const CATEGORIES = ['All', 'Pizza', 'Burger', 'Cake', 'Salad', 'Sandwich', 'Drink', 'Sushi', 'Pasta'];
const EMOJI_CAT = { All: '🍽️', Pizza: '🍕', Burger: '🍔', Cake: '🎂', Salad: '🥗', Sandwich: '🥪', Drink: '🥤', Sushi: '🍱', Pasta: '🍝' };

const Home = () => {
  const { user } = useAuth();
  const [foods, setFoods] = useState([]);
  const [loading, setLoading] = useState(true);
  const [category, setCategory] = useState('All');
  const [search, setSearch] = useState('');

  useEffect(() => {
    fetchFoods();
  }, [category]);

  const fetchFoods = async () => {
    setLoading(true);
    try {
      const params = {};
      if (category !== 'All') params.category = category.toLowerCase();
      if (search) params.search = search;
      const res = await foodAPI.getAllFoods(params);
      setFoods(res.data.foods);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    fetchFoods();
  };

  return (
    <div style={styles.page}>
      <Navbar />
      <div style={styles.container}>

        {/* Hero */}
        <div style={styles.hero}>
          <div>
            <h1 style={styles.heroTitle}>Order your<br />favourite food 🍕</h1>
            <p style={styles.heroSub}>Fast delivery, fresh meals — right to your door</p>
          </div>
          <div style={styles.heroEmoji}>🍔</div>
        </div>

        {/* Search */}
        <form onSubmit={handleSearch} style={styles.searchBar}>
          <span style={styles.searchIcon}>🔍</span>
          <input
            style={styles.searchInput}
            placeholder="Search pizza, burger, cake..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <button type="submit" style={styles.searchBtn}>Search</button>
        </form>

        {/* Categories */}
        <div style={styles.cats}>
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              style={{ ...styles.cat, ...(category === cat ? styles.catActive : {}) }}
              onClick={() => setCategory(cat)}
            >
              {EMOJI_CAT[cat]} {cat}
            </button>
          ))}
        </div>

        {/* Grid */}
        <div style={styles.sectionHeader}>
          <h2 style={styles.sectionTitle}>
            {category === 'All' ? 'All Items' : category}
          </h2>
          <span style={styles.count}>{foods.length} items</span>
        </div>

        {loading ? (
          <div style={styles.loading}>
            {[1,2,3,4,5,6].map(i => <div key={i} style={styles.skeleton} />)}
          </div>
        ) : foods.length === 0 ? (
          <div style={styles.empty}>
            <div style={styles.emptyIcon}>🍽️</div>
            <p style={styles.emptyText}>No items found</p>
          </div>
        ) : (
          <div style={styles.grid}>
            {foods.map(food => <FoodCard key={food._id} food={food} />)}
          </div>
        )}
      </div>
    </div>
  );
};

const styles = {
  page: { minHeight: '100vh', background: '#F8F6F2' },
  container: { maxWidth: '1100px', margin: '0 auto', padding: '1.5rem' },
  hero: {
    background: '#E8621A',
    borderRadius: '16px',
    padding: '2rem 2.5rem',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '1rem',
  },
  heroTitle: { fontSize: '24px', fontWeight: '600', color: '#fff', lineHeight: '1.3', marginBottom: '8px' },
  heroSub: { fontSize: '14px', color: 'rgba(255,255,255,0.85)' },
  heroEmoji: { fontSize: '72px' },
  searchBar: {
    background: '#fff',
    border: '0.5px solid #EBEBEB',
    borderRadius: '10px',
    padding: '10px 14px',
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    marginBottom: '1rem',
  },
  searchIcon: { fontSize: '16px' },
  searchInput: {
    flex: 1, border: 'none', outline: 'none',
    fontSize: '14px', background: 'transparent', color: '#1A1A1A',
  },
  searchBtn: {
    background: '#E8621A', color: '#fff',
    border: 'none', borderRadius: '8px',
    padding: '6px 16px', fontSize: '13px',
  },
  cats: { display: 'flex', gap: '8px', flexWrap: 'wrap', marginBottom: '1.5rem' },
  cat: {
    padding: '7px 16px', borderRadius: '20px',
    fontSize: '13px', border: '0.5px solid #EBEBEB',
    background: '#fff', color: '#888780',
  },
  catActive: { background: '#FDF0E8', borderColor: '#F5A06A', color: '#E8621A', fontWeight: '500' },
  sectionHeader: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1rem' },
  sectionTitle: { fontSize: '18px', fontWeight: '500' },
  count: { fontSize: '13px', color: '#888780' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '14px' },
  loading: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '14px' },
  skeleton: { height: '220px', background: '#EBEBEB', borderRadius: '12px', animation: 'pulse 1.5s infinite' },
  empty: { textAlign: 'center', padding: '4rem 0' },
  emptyIcon: { fontSize: '48px', marginBottom: '1rem' },
  emptyText: { color: '#888780', fontSize: '15px' },
};

export default Home;
